import React, { useState } from 'react';
import API from '../api/axios';
import { useNavigate } from 'react-router-dom';

const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [errorMessage, setErrorMessage] = useState('');
    const navigate = useNavigate();

    const handleLogin = async (e) => {
        e.preventDefault();
        setLoading(true);
        setErrorMessage('');
        try {
            const { data } = await API.post('/auth/login', { email, password });

            localStorage.setItem('token', data.token);
            localStorage.setItem('role', data.role);
            localStorage.setItem('userName', data.userName || data.email || 'User');
            localStorage.setItem('userId', data.userId);
            setErrorMessage('');
            navigate('/dashboard');
        } catch (err) {
            const message = err.response?.data?.message || "Invalid email or password";
            setErrorMessage(message);
            console.error('Login error:', message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={styles.loginPage}>
            <style>{`
                @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');

                * {
                    margin: 0;
                    padding: 0;
                    box-sizing: border-box;
                    font-family: 'Inter', sans-serif;
                }

                .background-gradient {
                    position: absolute;
                    width: 100%;
                    height: 100%;
                    background: radial-gradient(circle at 20% 30%, #ff00cc, transparent 40%),
                                radial-gradient(circle at 80% 70%, #00c6ff, transparent 40%),
                                linear-gradient(135deg, #1a1a2e, #16213e);
                    z-index: 0;
                }

                .login-container {
                    position: relative;
                    width: 100%;
                    max-width: 420px;
                    padding: 50px 40px;
                    background: rgba(20, 20, 30, 0.85);
                    border-radius: 20px;
                    box-shadow: 0 0 30px rgba(0, 198, 255, 0.4);
                    border: 1px solid rgba(255, 255, 255, 0.1);
                    z-index: 2;
                    animation: fadeIn 0.8s ease;
                }

                @keyframes fadeIn {
                    from { opacity: 0; transform: scale(0.95); }
                    to { opacity: 1; transform: scale(1); }
                }

                .login-header {
                    text-align: center;
                    margin-bottom: 35px;
                }

                .welcome-title {
                    font-size: 28px;
                    font-weight: 700;
                    background: linear-gradient(90deg, #00c6ff, #ff00cc);
                    -webkit-background-clip: text;
                    -webkit-text-fill-color: transparent;
                    margin-bottom: 12px;
                }

                .welcome-subtitle {
                    font-size: 15px;
                    color: rgba(255, 255, 255, 0.7);
                }

                .form-group {
                    position: relative;
                    margin-bottom: 28px;
                }

                .form-input {
                    width: 100%;
                    padding: 18px 16px 6px 16px;
                    font-size: 15px;
                    border: 2px solid rgba(255, 255, 255, 0.2);
                    border-radius: 12px;
                    background: transparent;
                    color: #fff;
                    transition: all 0.3s ease;
                }

                .form-input:focus {
                    outline: none;
                    border-color: #00c6ff;
                    box-shadow: 0 0 12px rgba(0, 198, 255, 0.5);
                }

                .form-label {
                    position: absolute;
                    left: 16px;
                    top: 50%;
                    transform: translateY(-50%);
                    font-size: 14px;
                    color: rgba(255, 255, 255, 0.6);
                    pointer-events: none;
                    transition: all 0.3s ease;
                }

                .form-input:focus + .form-label,
                .form-input:not(:placeholder-shown) + .form-label {
                    top: 8px;
                    font-size: 12px;
                    color: #00c6ff;
                }

                .login-button {
                    width: 100%;
                    padding: 15px;
                    background: linear-gradient(135deg, #00c6ff 0%, #ff00cc 100%);
                    color: white;
                    border: none;
                    border-radius: 12px;
                    font-size: 15px;
                    font-weight: 600;
                    cursor: pointer;
                    transition: transform 0.2s ease, box-shadow 0.2s ease;
                    margin-top: 12px;
                }

                .login-button:hover {
                    transform: translateY(-2px);
                    box-shadow: 0 6px 20px rgba(255, 0, 204, 0.4);
                }

                .login-button:disabled {
                    background: #555;
                    cursor: not-allowed;
                }

                .error-message {
                    background: rgba(255, 0, 0, 0.15);
                    color: #ff4d4d;
                    padding: 12px 16px;
                    border-radius: 12px;
                    font-size: 14px;
                    margin-bottom: 20px;
                    border: 1px solid rgba(255, 0, 0, 0.3);
                    text-align: center;
                }

                @media (max-width: 480px) {
                    .login-container {
                        padding: 35px 28px;
                        margin: 0 16px;
                    }
                }
            `}</style>

            <div className="background-gradient"></div>

            <div className="login-container">
                <div className="login-header">
                    <h1 className="welcome-title">Welcome Back</h1>
                    <p className="welcome-subtitle">Sign in to access your dashboard</p>
                </div>

                {errorMessage && (
                    <div className="error-message">
                        {errorMessage}
                    </div>
                )}

                <form onSubmit={handleLogin}>
                    <div className="form-group">
                        <input
                            type="email"
                            className="form-input"
                            placeholder=" "
                            value={email}
                            onChange={e => setEmail(e.target.value)}
                            required
                        />
                        <label className="form-label">Email</label>
                    </div>

                    <div className="form-group">
                        <input
                            type="password"
                            className="form-input"
                            placeholder=" "
                            value={password}
                            onChange={e => setPassword(e.target.value)}
                            required
                        />
                        <label className="form-label">Password</label>
                    </div>

                    <button 
                        type="submit" 
                        className="login-button"
                        disabled={loading}
                    >
                        {loading ? 'Signing in...' : 'Sign in'}
                    </button>
                </form>
            </div>
        </div>
    );
};

const styles = {
    loginPage: {
        minHeight: '100vh',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        background: '#0f0f1a',
        padding: '20px',
        position: 'relative',
        overflow: 'hidden',
    },
};

export default Login;
